[
  {
    "text": "A textual analysis of the 15 FAIR guiding principles confirms that none of them refers to human cognitive load, interface complexity, or perceptual accessibility.",
    "topic": "FAIR scope limitation"
  },
  {
    "text": "In published FAIR assessment frameworks (e.g., FAIRshake, ARDC FAIR self-assessment), cognitive load measures are absent from all evaluation items.",
    "topic": "Assessment instruments"
  },
  {
    "text": "A systematic review of repository design guidelines reveals that cognitive accessibility recommendations appear in separate usability standards (e.g., ISO 9241) and are not integrated into FAIR implementation recipes.",
    "topic": "Design guidance separation"
  },
  {
    "text": "Controlled experiments comparing two FAIR-compliant repositories with identical metadata quality but different interface designs yield significantly different task-completion times and perceived cognitive load on the NASA-TLX.",
    "topic": "Measurable cognitive gap"
  }
]
